class Solution {
public:
    int shortestMatchingSubstring(string s, string p) {
        int m = p.size(), n = s.size();
        int l = 0, r = m - 1;
        while (l < m && p[l] != '*') l++;
        while (r >= 0 && p[r] != '*') r--;
        if (l > r) return 0;
        int res = INT_MAX;
        for (int i = 0; i < n; i++) {
            int j = i, k = l;
            while (k < m) {
                if (p[k] == '*') {
                    k++;
                    if (k > r) break;
                    while (k < m && p[k] == '*') k++;
                    if (k > r) break;
                    while (j < n && (p[k] != s[j] || p[k] == '*')) j++;
                } else if (p[k] != s[j]) break;
                j++;
                k++;
            }
            if (k > r) res = min(res, j - i);
        }
        return res == INT_MAX ? -1 : res;
    }
};
